const saveBlog = async (status = "published", publishExternally = false) => {
  if (!generatedBlog) return;

  try {
    const blogData = {
      title: generatedBlog.title,
      excerpt: generatedBlog.excerpt,
      content: generatedBlog.content,
      category: generatedBlog.category || selectedCategory,
      tags: generatedBlog.tags || [],
      tone: generatedBlog.tone || selectedTone,
      wordCount: generatedBlog.wordCount || getWordCount(generatedBlog.content),
      readTime: generatedBlog.readTime || getReadTime(generatedBlog.content),
      slug: generatedBlog.slug || generateSlug(generatedBlog.title),
      seoKeywords: generatedBlog.seoKeywords || [],
      coverImagePrompt: generatedBlog.coverImagePrompt || "",
      qualityScore: qualityScore?.overall || null,
      status,
      icon: getCategoryInfo(generatedBlog.category || selectedCategory).icon,
      createdAt: serverTimestamp(),
      updatedAt: serverTimestamp(),
      // External platform URLs (filled after publishing)
      devtoUrl: null,
      hashnodeUrl: null,
    };

    // Save to Firestore first
    const docRef = await addDoc(collection(db, BLOG_COLLECTION), blogData);
    addToast(
      status === "published" ? "✅ Saved to gallery!" : "📝 Saved as draft!",
      "success"
    );

    // Publish externally if requested
    if (publishExternally && status === "published") {
      addToast("🚀 Publishing to Dev.to & Hashnode...", "info");

      try {
        const externalResult = await publishToExternalPlatforms(blogData);

        const updateData = {};

        // Update Firestore with external URLs
        if (externalResult.results?.devto?.success) {
          updateData.devtoUrl = externalResult.results.devto.url;
          addToast(`✅ Live on Dev.to!`, "success");
        } else if (externalResult.results?.devto) {
          addToast(`⚠️ Dev.to failed: ${externalResult.results.devto.error}`, "warning");
        }

        if (externalResult.results?.hashnode?.success) {
          updateData.hashnodeUrl = externalResult.results.hashnode.url;
          addToast(`✅ Live on Hashnode!`, "success");
        } else if (externalResult.results?.hashnode) {
          addToast(`⚠️ Hashnode failed: ${externalResult.results.hashnode.error}`, "warning");
        }

        // Update the Firestore document with external URLs
        if (Object.keys(updateData).length > 0) {
          await updateDoc(doc(db, BLOG_COLLECTION, docRef.id), updateData);
        }
      } catch (externalErr) {
        addToast(`⚠️ External publish failed: ${externalErr.message}`, "error");
        // Blog is still saved locally, just not published externally
      }
    }

    // Reset form
    setGeneratedBlog(null);
    setTopic("");
    setDetails("");
    setCustomTags("");
    setSeoKeywords("");
    setQualityScore(null);
    setImprovementSuggestions(null);
    setShowGenerator(false);
    setActiveGenTab("compose");
  } catch (err) {
    console.error(err);
    addToast("Failed to save blog.", "error");
  }
};
